from langchain_community.llms import Ollama
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser

loose_prompt = ChatPromptTemplate.from_template("""
You are a helpful assistant. Answer the question as best you can.

CONTEXT: {context}
QUESTION: {question}
ANSWER:
""")

strict_prompt = ChatPromptTemplate.from_template("""
You are a strict University Student Handbook assistant.
Answer using ONLY the context below. If the answer is not present, respond with:
"I don't know. That information is not available in the provided handbook sections."
Do NOT guess or infer.

CONTEXT: {context}
QUESTION: {question}
ANSWER:
""")

context = "\n\n".join([doc.page_content for doc in db.similarity_search(test_query, k=3)])

for temp in [0.0, 1.0]:
    for label, prompt in [("Loose", loose_prompt), ("Strict", strict_prompt)]:
        llm = Ollama(model="gemma3:1b", temperature=temp)
        chain = prompt | llm | StrOutputParser()
        response = chain.invoke({"context": context, "question": test_query})
        print(f"\n--- {label} Prompt | Temperature={temp} ---")
        print(response)

